const OP_SCAFFOLD_STATUS: &str = "truthful-bidir.scaffold_status";
const CAP_SCAFFOLD_STATUS: &str = "truthful-bidir.scaffold_status";

fn test_signing_key() -> fcp_crypto::ed25519::Ed25519SigningKey {
    fcp_crypto::ed25519::Ed25519SigningKey::generate()
}

fn test_capability_token(
    signing_key: &fcp_crypto::ed25519::Ed25519SigningKey,
    operation: &str,
) -> CapabilityToken {
        let now = chrono::Utc::now();
        CapabilityToken::from_raw(
            fcp_crypto::cose::CapabilityTokenBuilder::new()
            .capability_id(CAP_SCAFFOLD_STATUS)
            .zone_id("z:work")
            .principal("user:test")
            .issuer("node:test")
            .operations(&[operation])
            .validity(now, now + chrono::Duration::hours(1))
            .sign(signing_key)
            .expect("test capability token should sign"),
    )
}

fn base_handshake(signing_key: &fcp_crypto::ed25519::Ed25519SigningKey) -> HandshakeRequest {
    HandshakeRequest {
        protocol_version: "2.0.0".into(),
        zone: ZoneId::work(),
        zone_dir: None,
        host_public_key: signing_key.verifying_key().to_bytes(),
        nonce: [0u8; 32],
        capabilities_requested: vec![CapabilityId::from_static(CAP_SCAFFOLD_STATUS)],
        host: None,
        transport_caps: None,
        requested_instance_id: None,
    }
}

fn base_invoke(
    connector_id: &ConnectorId,
    operation: &str,
    signing_key: &fcp_crypto::ed25519::Ed25519SigningKey,
) -> InvokeRequest {
    InvokeRequest {
        r#type: "invoke".into(),
        id: RequestId::new("req_1"),
        connector_id: connector_id.clone(),
        operation: OperationId::from_static(operation),
        zone_id: ZoneId::work(),
        input: serde_json::json!({}),
        capability_token: test_capability_token(signing_key, operation),
        holder_proof: None,
        context: None,
        idempotency_key: None,
        lease_seq: None,
        deadline_ms: None,
        correlation_id: None,
        provenance: None,
        approval_tokens: Vec::new(),
    }
}

