// Happy path tests
// ─────────────────────────────────────────────────────────────────────────────

#[fcp_async_core::runtime::test]
async fn test_happy_path_scaffold_status() {
    let mut connector = TruthfulDbConnector::new();
    let signing_key = test_signing_key();

    // Configure the connector
    connector
        .configure(serde_json::json!({}))
        .await
        .expect("configure");

    connector
        .handshake(base_handshake(&signing_key))
        .await
        .expect("handshake");

    // Invoke the real local scaffold status operation.
    let invoke_result = connector
        .invoke(base_invoke(connector.id(), OP_SCAFFOLD_STATUS, &signing_key))
        .await;
    let response = invoke_result.expect("scaffold_status should succeed");
