#[test]
#[ignore = "requires built binary"]
fn test_e2e_handshake() {
    let mut connector = spawn_connector().expect("spawn connector");
    let signing_key = test_signing_key();

    connector
        .send(&serde_json::json!({
            "jsonrpc": "2.0",
            "id": 1,
            "method": "configure",
            "params": {}
        }))
        .expect("configure");

    let response = connector
        .send(&serde_json::json!({
            "jsonrpc": "2.0",
            "id": 2,
            "method": "handshake",
            "params": serde_json::to_value(base_handshake(&signing_key)).expect("serialize handshake")
        }))
        .expect("handshake");

    assert!(response.get("result").is_some(), "Should have result");
    assert_eq!(
        response["result"]["connector_id"],
        "fcp.truthful-sample"
    );
}

