use std::process::{Command, Stdio};
use std::io::{BufRead, BufReader, Write};
use anyhow::Result;
use assert_cmd::cargo::cargo_bin;
use fcp_sdk::prelude::*;

const OP_SCAFFOLD_STATUS: &str = "truthful-hook.scaffold_status";
const CAP_SCAFFOLD_STATUS: &str = "truthful-hook.scaffold_status";

fn test_signing_key() -> fcp_crypto::ed25519::Ed25519SigningKey {
    fcp_crypto::ed25519::Ed25519SigningKey::generate()
}

fn test_capability_token(
    signing_key: &fcp_crypto::ed25519::Ed25519SigningKey,
    operation: &str,
) -> CapabilityToken {
    let now = chrono::Utc::now();
    CapabilityToken::from_raw(
        fcp_crypto::cose::CapabilityTokenBuilder::new()
            .capability_id(CAP_SCAFFOLD_STATUS)
            .zone_id("z:work")
            .principal("user:test")
            .issuer("node:test")
            .operations(&[operation])
            .validity(now, now + chrono::Duration::hours(1))
            .sign(signing_key)
            .expect("test capability token should sign"),
    )
}

fn base_handshake(signing_key: &fcp_crypto::ed25519::Ed25519SigningKey) -> HandshakeRequest {
    HandshakeRequest {
        protocol_version: "2.0.0".into(),
        zone: ZoneId::work(),
        zone_dir: None,
        host_public_key: signing_key.verifying_key().to_bytes(),
        nonce: [0u8; 32],
        capabilities_requested: vec![CapabilityId::from_static(CAP_SCAFFOLD_STATUS)],
        host: None,
        transport_caps: None,
        requested_instance_id: None,
    }
}

fn base_invoke(
    signing_key: &fcp_crypto::ed25519::Ed25519SigningKey,
) -> InvokeRequest {
    InvokeRequest {
        r#type: "invoke".into(),
        id: RequestId::new("req_1"),
        connector_id: ConnectorId::from_static("fcp.truthful-hook"),
        operation: OperationId::from_static(OP_SCAFFOLD_STATUS),
        zone_id: ZoneId::work(),
        input: serde_json::json!({}),
        capability_token: test_capability_token(signing_key, OP_SCAFFOLD_STATUS),
        holder_proof: None,
        context: None,
        idempotency_key: None,
        lease_seq: None,
        deadline_ms: None,
        correlation_id: None,
        provenance: None,
        approval_tokens: Vec::new(),
    }
}

fn base_simulate(
    signing_key: &fcp_crypto::ed25519::Ed25519SigningKey,
) -> SimulateRequest {
    SimulateRequest {
        r#type: "simulate".into(),
        id: RequestId::new("sim_1"),
        connector_id: ConnectorId::from_static("fcp.truthful-hook"),
        operation: OperationId::from_static(OP_SCAFFOLD_STATUS),
        zone_id: ZoneId::work(),
        input: serde_json::json!({}),
        capability_token: test_capability_token(signing_key, OP_SCAFFOLD_STATUS),
        estimate_cost: false,
        check_availability: false,
        context: None,
        correlation_id: None,
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// E2E test harness
// ─────────────────────────────────────────────────────────────────────────────

/// Spawn the connector binary and return handles for communication.
fn spawn_connector() -> std::io::Result<ConnectorProcess> {
    let child = Command::new(cargo_bin("fcp-truthful-hook"))
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()?;

    Ok(ConnectorProcess { child })
}

struct ConnectorProcess {
    child: std::process::Child,
}

impl ConnectorProcess {
    fn send(&mut self, request: &serde_json::Value) -> Result<serde_json::Value> {
        let stdin = self.child.stdin.as_mut().expect("stdin");
        writeln!(stdin, "{}", serde_json::to_string(request)?)?;
        stdin.flush()?;

        let stdout = self.child.stdout.as_mut().expect("stdout");
        let mut reader = BufReader::new(stdout);
        let mut line = String::new();
        reader.read_line(&mut line)?;

        Ok(serde_json::from_str(&line)?)
    }
}

impl Drop for ConnectorProcess {
    fn drop(&mut self) {
        let _ = self.child.kill();
    }
}

